import React from 'react';
import './credenciales.css';

// Cambiamos a Mayúscula inicial
function CredencialesUsuario() {
    return (
        <div className="contenedor_credenciales_usuario">
            <div className="espacios_de_credenciales">
                <label htmlFor="Nombre" className='label_credenciales'>Nombre:</label>
                <input type="email" name="" id="" placeholder='Nombre' className='estilo_de_input_1'/>                
            </div>
            <div className='espacios_de_credenciales'>
                <label htmlFor="" className='label_credenciales'>Grado:</label>
                <select name="" id="" className='estilo_de_input_2'>
                    <option value="" children='estilos_de_opciones_grado' disabled selected>Seleciona Grado</option>
                    <option value="" children='estilos_de_opciones_grado'>4/5</option>
                    <option value="" children='estilos_de_opciones_grado'>6/7</option>
                    <option value="" children='estilos_de_opciones_grado'>8/9</option>
                    <option value="" children='estilos_de_opciones_grado'>10/11</option>
                </select>
            </div>
            <button type="submit" className='btn_Comenzar'>Comenzar</button>
        </div>
    );
}

export default CredencialesUsuario;
